                                                    v-on:click="showImg(item.ATTACHMENTFULLPATH, item.MESSAGE_BOARD_FILE_NAME)"
                                                    :title="$t('View')" :value="item.TASK_ID"
                                                    :fileName="item.MESSAGE_BOARD_FILE_NAME"
                                                    :filePath="item.ATTACHMENTFULLPATH"
                                                    :fileType="JSON.parse(AttachmentList[0].MESSAGE_BOARD_FILE_DESC).ContentType"
