                                                    <em class="fa fa-eye"></em><br />
                                                </a>
                                                <a href="javascript:;"
                                                    class="text-primary round-icons mr-2 downloadfile"
                                                    v-on:click="DownloadAttachment(item, item.MESSAGE_BOARD_FILE_ID)"
