                                            </div>
                                        </div>

                                        <div class="img-ico text-center p-4 ticket-attachments">
                                            <em v-if="!setImageIcon(item)" class="fa fa-file-video-o"></em>
                                            <em v-else-if="setImageIcon(item) == 'word-ico.png'"
                                                class="fa fa-file-word-o"></em>
                                            <em v-else-if="setImageIcon(item) == 'excel-ico.png'"
                                                class="fa fa-file-excel-o"></em>
                                            <em v-else-if="setImageIcon(item) == 'pdf-ico.png'"
                                                class="fa fa-file-pdf-o"></em>
                                            <img v-else-if="setImageIcon(item) == 'png-ico.png'" alt=""
                                                class="img-fluid"
                                                style="width: auto; height: 102px; min-height: 102px;" />
                                            <em v-else-if="setImageIcon(item) == 'audio-ico.png'"
                                                class="fa fa-file-audio-o"></em>
                                            <em v-else-if="setImageIcon(item) == 'file-ico.png'"
                                                class="fa fa-file-text-o"></em>
                                            <template>
                                                <img v-if="setImageIcon(item) != '/Content/Responsive/images/png-ico.png'"
                                                    :src="setImageIcon(item)" alt="" class="img-fluid"
                                                    style="width: auto; height: 102px; min-height: 102px;" />
                                                <img :src="item.ATTACHMENTFULLPATH" alt="" class="img-fluid"
                                                    style="width: auto; height: 102px; min-height: 102px;" />
                                            </template>
                                        </div>
                                        <hr class="my-1" />
                                        <div class="col-12 p-0 mx-0 align-items-end float-left">
                                            <div class="col-12 textelipsis px-2">{{ item.MESSAGE_BOARD_FILE_NAME }}
                                            </div>
                                            <div class="col-md-12 px-2 py-1 bg-light mt-1 float-left">
                                                <small class="float-left textelipsis col-6 p-0"><span>{{ item.ASSIGNEDBY
                                                        }}</span></small>
