    </section>
</template>

<script>
import DataServices from "@/services/DataService";
export default {
    props: {
        AttachmentData: {
            type: Array,
            required: true
        },
        galleryImages: {
            type: Array,
            required: false
        },
        viewMode: {
            type: String,
            required: false
        },
        ListViewAttachment: {
            type: Number,
            required: false
        }
    },
    data() {
        return {
            AttachmentList: [],
            ListViewAttachment: 0,
            GalleryImages: [],
            NoRecords: false,
            visible: false,
            UserId: null,
            isLoading: false,
            index: 0,
            GpxFileXmlData: '',
            ShowGPXFile: false,
            videoFilePath: '',
            gpxFilePath: ''
        }
    },
    watch: {
        AttachmentData: function (val) {
            //debugger;
            var vm = this;
            vm.AttachmentList = val;
            if (vm.AttachmentList.length > 0) {
                vm.NoRecords = false;
            }
            else {
                vm.AttachmentList = [];
                vm.NoRecords = true;
            }
        }
    },
    created() {
        debugger
        var vm = this;
        vm.ListViewAttachment = this.ListViewAttachment;
        //setTimeout(() => {
        vm.UserId = vm.GetUserInfo.ID;
        vm.GalleryImages = vm.galleryImages;
        if (typeof vm.AttachmentData != "undefined" && vm.AttachmentData[0].MESSAGE_BOARD_FILE_ID != null) {

            vm.AttachmentList = vm.AttachmentData;
            vm.NoRecords = false;
        }
        else {
            vm.AttachmentList = [];
            vm.NoRecords = true;
        }
        //}, 1000);
    },
    methods: {
        Close: function () {
            var vm = this;
            vm.$parent.isAttachmentShowPopup = false;
        },
        handleHide: function () {
            this.visible = false
        },
        showImg: function (attachmentPath, attachmentName) {
            //debugger;
            var vm = this;
            vm.$parent.galleryImages = [];
            vm.$emit('open-image', attachmentPath, attachmentName);
            vm.$parent.visible = true;
            //vm.$parent.index = index; 
        },
        CheckExtension(fileDescription, GeoFilePath) {
            var checkExt = 0
            if (GeoFilePath == null || GeoFilePath == "") {
                if (fileDescription != "") {
                    if (JSON.parse(fileDescription).Extension == 'jpg' || JSON.parse(fileDescription).Extension == 'jpeg' || JSON.parse(fileDescription).Extension == 'png' || JSON.parse(fileDescription).Extension == 'gif') {
                        checkExt = 1;
                    } else {
                        checkExt = 0;
                    }
                } else {
                    checkExt = 0;
                }
                return checkExt;
            }
        },
        setImageIcon(item) {
            var vm = this;
            var imageIcon = "/Content/Responsive/images/";
            var extension = vm.getExtension(item.MESSAGE_BOARD_FILE_NAME);
            //var extension = '';
            switch (extension.toLowerCase()) {
                case "doc":
                case "docx":
                    imageIcon = "word-ico.png";
                    break;
                case "xlsx":
                case "xls":
                    imageIcon = "excel-ico.png";
                    break;
                case "pdf":
                    imageIcon = "pdf-ico.png";
                    break;
                case "jpg":
                case "jpeg":
                case "png":
                case "gif":
                case "bmp":
                    imageIcon = "png-ico.png";
                    break;
                case "webm":
                case "mov":
                case "mpv":
                case "mp4":
                case "avi":
                    imageIcon = ""; //"video-ico.png";
                    break;
                case "mp3":
                case "wav":
                    imageIcon = "audio-ico.png";
                    break;
                default:
                    imageIcon = "file-ico.png";
                    break;
            }
            return imageIcon;

        },
        getExtension(fileName) {
            if (!fileName || typeof fileName !== "string") return ""; // handle null/undefined/non-string
            const baseName = fileName.split(/[\\/]/).pop();
            const pos = baseName.lastIndexOf(".");
            if (!baseName || pos < 1) return "";
            return baseName.slice(pos + 1).toLowerCase();
        },

        DownloadAttachment(items, clickedNoteId) {
            const vm = this;
            vm.isLoading = true;

            // ✅ Force items into an array if it's a single object
            const attachmentList = Array.isArray(items) ? items : [items];

            const validAttachments = attachmentList.filter(element =>
                element.MESSAGE_BOARD_FILE_NAME &&
                element.MESSAGE_BOARD_FILE_PATH &&
                element.MESSAGE_BOARD_FILE_ID == clickedNoteId
            );

            validAttachments.forEach(element => {
                const param = `filePath=${element.MESSAGE_BOARD_FILE_PATH}&fileName=${element.MESSAGE_BOARD_FILE_NAME}`;
                DataServices.DownloadFile(param)
                    .then(response => {
                        const byteData = response.data;
                        const contentType = JSON.parse(element.MESSAGE_BOARD_FILE_DESC || '{}').ContentType || 'application/octet-stream';
                        const fileURL = `data:${contentType};base64,${byteData}`;
                        const fileLink = document.createElement('a');
                        fileLink.href = fileURL;
                        fileLink.setAttribute('download', element.MESSAGE_BOARD_FILE_NAME);
                        document.body.appendChild(fileLink);
                        fileLink.click();
                        document.body.removeChild(fileLink);
                    })
                    .catch(error => {
                        console.error(`Error downloading ${element.MESSAGE_BOARD_FILE_NAME}:`, error);
                    });
            });

            vm.isLoading = false;
        },

        // DeleteAttachment(item) {
        //     debugger;
        //     const vm = this;
        //     vm.confirmR(vm.$t("ConfirmDelete"), true, vm.$t("Remove"), function () {
        //         if (!item || !item.MESSAGE_BOARD_FILE_ID) {
        //             vm.ShowAlert(vm.$t("InvalidAttachmentData"), "error", true, vm.$t("Alert"));
        //             return;
        //         }
        //         vm.confirmR(vm.$t("ConfirmDelete"), true, vm.$t('Remove'), function () {
        //             var postJSON = {
        //                 ids: item.MESSAGE_BOARD_FILE_ID,
        //                 //moduleName: "RequestTimeList",
        //                 moduleName: "",
        //                 subModuleCode: "",
        //                 refCode: 'TALYGEN_MESSAGE_BOARD_FILES'
        //             };
        //             vm.isLoading = true;
        //             var objectPostString = JSON.stringify(postJSON);
        //             DataServices.CommonCommonDelete(objectPostString).then(function (response) {
        //                 vm.isLoading = false;                        
        //                 if (response.data[0].Status == "Success") {
        //                     vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Attchment')]), 'success', true, vm.$t('Alert'));
        //                     vm.$parent.FetchData();                            
        //                 }
        //                 else {
        //                      vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Attchment')]), "warning", true, vm.$t("Alert"));
        //                 }
        //             });
        //         });
        //     });
        // },

    }

}
</script>