<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <div class="right-content">
            <div class="listing">
                <div class="tab-pane mb-0">
                    <div id="myTabContent" class="tab-content" style="display: block;">
                        <div id="PROJECT_OVERVIEW" role="tabpanel" aria-labelledby="dashboard-tab"
                            class="tab-pane fade border-0 p-0 no-border-mb project-tab active show">
                            <ul class="dashbord-widget">
                                <li class="one_wid" style="cursor: pointer;">
                                    <h3>{{ TaskCountData !== null && TaskCountData !== undefined ? TaskCountData : 0 }}<br><span>{{ $t("Total Tasks") }}</span></h3>
                                    <i aria-hidden="true" class="fa fa-list-alt"></i>
                                </li>
                                <li class="two_wid" style="cursor: pointer;">
                                    <h3>{{ ApproveData !== null && ApproveData !== undefined ? ApproveData : 0 }}<br><span>{{ $t("Approved") }}</span></h3>
                                    <i aria-hidden="true" class="fa fa-check-circle"></i>
                                </li>
                                <li class="three_wid" style="cursor: pointer;">
                                    <h3>{{ RejectData !== null && RejectData !== undefined ? RejectData : 0 }}<br><span>{{ $t("Rejected") }}</span></h3>
                                    <i aria-hidden="true" class="fa fa-calendar-times-o"></i>
                                </li>
                                <li class="four_wid" style="cursor: pointer;">
                                    <h3>{{ PendingData !== null && PendingData !== undefined ? PendingData : 0 }}<br><span>{{ $t("Pending") }}</span></h3>
                                    <i aria-hidden="true" class="fa fa-exclamation-triangle"></i>
                                </li>
                            </ul>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <tg-list :IsShowAction="true" ModuleName="" SubModuleCode="" :LegendArray="[]"
            :RenderRowActionMethod="renderActions" v-on:ActionButtonClick="actionButtonClick" :widgets="[]"
            IdentityColumn="PROJECT_ID" :listType="['List']" :ListData="RequestTimeData" :HeaderData="Headers"
            :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :SearchFields="leftSearchFields"
            IsSearchFieldsOnTop="true" :ListDataCallBackFunction="FetchData" :showCheckBox="false" :SortExp="SortExp"
            :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')" :HeaderText="$t('RequestTime')"
            v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata">
            <template v-slot:slotdata="{ data }">

                <template v-if="data.column.COLUMN_NAME == 'CREATED_AT'">
                    <span class="text-dark" :title="$options.filters.formatDate(data.row.CREATED_AT)">
                        {{ $options.filters.formatDate(data.row.CREATED_AT) }}
                    </span>
                </template>

                <template v-if="data.column.COLUMN_NAME == 'REQUEST_TIME_SEC'">
                    {{ convertSecondsToHHMMSSNew(data.row.REQUEST_TIME_SEC) }}
                </template>
                
                <template v-if="data.column.COLUMN_NAME == 'REQUEST_COMMENT'" >




                   
                    <div class="text-center single-action" title="" @click="openCommentPopup(data.row, data.row.REQUEST_COMMENT)">
                         <a   href="javascript:;" class="text-dark">
                            <em aria-hidden="true" class="fa fa-commenting-o"></em>
                            <span v-if="data.row.COMMENT_COUNT > 0" class="noti-circle noti-green">{{ data.row.COMMENT_COUNT }}</span>
                             <span v-else class="noti-circle noti-green">0</span>
                        </a>
                        <!-- <em class="fa fa-commenting-o"  style="cursor:pointer"></em>
                        <span v-if="data.row.COMMENT_COUNT > 0" class="comment-count">{{ data.row.COMMENT_COUNT }}</span> -->
                    </div>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'ATTACHMENTFULLPATH'">
                    <div class=" text-center single-action" title="Attachment" @click="openAttachemntPopup(data.row, data.row.FILECOUNT)">
                      <a href="javascript:;" class="text-dark">
                        <em aria-hidden="true" class="fa fa-paperclip"></em>
                        <span v-if="data.row.FILECOUNT>0" class="noti-circle noti-blue">{{ data.row.FILECOUNT }}</span>
                        <span v-else class="noti-circle noti-blue">0</span>
                    </a>
                    </div>
                </template>
                
                <template v-if="data.column.COLUMN_NAME == 'Status'">
                    <span :class="{
                        'px-2 text-center text-white d-block bg-danger': data.row.IS_APPROVE_REJECT === 0,
                        'px-2 text-center text-white d-block bg-info': data.row.IS_APPROVE_REJECT === null,
                        'px-2 text-center text-white d-block bg-success': data.row.IS_APPROVE_REJECT === 1,
                        'text-dark': data.row.IS_APPROVE_REJECT !== 0 && data.row.IS_APPROVE_REJECT !== 1 && data.row.IS_APPROVE_REJECT !== null}">
                        {{
                            data.row.IS_APPROVE_REJECT === 0 ? 'Rejected' :
                            data.row.IS_APPROVE_REJECT === null ? 'Pending' :
                            data.row.IS_APPROVE_REJECT === 1 ? 'Approved' :
                            ''
                        }}
                    </span>
                </template>
            </template>
        </tg-list>
        <AddComment v-if="ShowAddComment" :MessageBoardData="MessageBoardData"></AddComment>
        <ApprovalPopup v-if="ShowApprovalPopup" :MessageBoardData="MessageBoardData"></ApprovalPopup>
        <RejectedPopup v-if="ShowRejectedPopup" :MessageBoardData="MessageBoardData"></RejectedPopup>
        <TimerAttachmentShow v-if="isAttachmentShowPopup" :AttachmentData="AttachmentData"></TimerAttachmentShow>      
    </section>
</template>

<script>
import Schema from '../../Project/RequestTime/RequestTimeListingSchema.js';
import DataServices from '../../../services/DataService';
import AddComment from './AddComment.vue';
import ApprovalPopup from './ApprovalPopup.vue';
import RejectedPopup from './RejectedPopup.vue';
import TimerAttachmentShow from '../../../components/Modal/TimerAttachmentShow.vue';
export default {
    components: {        
    AddComment,
    ApprovalPopup,
    RejectedPopup,
    TimerAttachmentShow
  },
    data() {
        return {
            isLoading: false,
            Headers: [{
                "COLUMN_NAME": "TASK_NAME",
                "DATA_TYPE": "text",
                "SORTABLE": true,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Task Name',
                "DISPLAY_ORDER": 1,
            },
            {
                "COLUMN_NAME": "REQUEST_TITLE",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Title',
                "DISPLAY_ORDER": 2,
            },
            {
                "COLUMN_NAME": "REQUEST_COMMENT",
                "DATA_TYPE": "Date",
                "SORTABLE": true,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Comment',
                "DISPLAY_ORDER": 3,
                settings: {
                    isInSlot: true
                }
            },
            {
                "COLUMN_NAME": "ATTACHMENTFULLPATH",
                "DATA_TYPE": "Date",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Attachment',
                "DISPLAY_ORDER": 4,
                settings: {
                    isInSlot: true
                }
            },
            {
                "COLUMN_NAME": "ASSIGNEDBY",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Requested By',
                "DISPLAY_ORDER": 5,
            },
            {
                "COLUMN_NAME": "REQUEST_TO",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Requested To',
                "DISPLAY_ORDER": 6,
            },
            {
                "COLUMN_NAME": "CREATED_AT",
                "DATA_TYPE": "Date",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Requested on',
                "DISPLAY_ORDER": 7,
                settings: {
                    isInSlot: true
                }
            },
            {
                "COLUMN_NAME": "REQUEST_TIME_SEC",
                "DATA_TYPE": "Date",
                "SORTABLE": true,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Requested Time (Hours)',
                "DISPLAY_ORDER": 8,
                settings: {
                    isInSlot: true
                }
            },
            {
                "COLUMN_NAME": "APPROVED_TIME",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Approved Time',
                "DISPLAY_ORDER": 9,
               
            },
            {
                "COLUMN_NAME": "Status",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Status',
                "DISPLAY_ORDER": 10,
                settings: {
                    isInSlot: true
                }
            }
            ],
            SortBy: '',
            SortExp: '',
            PageSize: "10",
            PageNumber: "1",
            TotalRecords: 0,
            CurrentPage: 1,
            ShowAddComment:false,
            ShowApprovalPopup:false,
            ShowRejectedPopup:false,
            isAttachmentShowPopup:false,
            TotalPages: 0,
            noRecords: false,
            searchCondition: '',
            minutesPerHour: 60,
            secondsPerMinute: 60,
            RequestTimeData: [],
            listheaderbuttons: Schema.buttons,
            listActions: Schema.listActions,
            leftSearchFields: Schema.leftsearchSchema,
            CompanyId: null,
            Userid: null,
            TaskName: '',
            searchBy: '',
            Title: '',
            Status: '',
           search: '',
            TaskCountData: 0,
            ApproveData: 0,
            PendingData: 0,
            RejectData: 0,
            MessageBoardData: '',
            AttachmentData:[]
        }
    },
    created: async function () {     
        debugger   
        var vm = this;
        vm.CompanyId = this.GetUserInfo.CompanyId;
        vm.Userid = this.GetUserInfo.ID;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.FetchData();
        if (vm.UserType === 'NU' || vm.UserType === 'CL') {
        vm.IsShowAction = false;
        const statusColumn = vm.Headers.find(h => h.COLUMN_NAME === 'Status');
        if (statusColumn) {
            statusColumn.VISIBLE = false;
        }
    }
    },
    methods: {
        openCommentPopup(itm){            
            var vm = this;
            vm.MessageBoardData = itm;
            vm.ShowAddComment = true;
        },
        ApprovePopup(itm){  
            var vm = this; 
            debugger
            vm.MessageBoardData = itm;           
            vm.ShowApprovalPopup = true;
        },
        RejectPopup(itm){  
            debugger          
            var vm = this;
            vm.MessageBoardData = itm;
            vm.ShowRejectedPopup = true;
        },
        openAttachemntPopup(itm){
            debugger
            var vm = this;
            vm.AttachmentData[0]=itm;
            vm.isAttachmentShowPopup=true; 
        },
        convertSecondsToHHMMSSNew: function (intSecondsToConvert) {
            var hours = this.convertHours(intSecondsToConvert);
            var minutes = this.getRemainingMinutes(intSecondsToConvert);
            minutes = minutes == 60 ? "00" : minutes;
            var seconds = this.getRemainingSeconds(intSecondsToConvert);
            if (hours < 10) hours = "0" + hours;
            if (minutes < 10) minutes = "0" + minutes;
            if (seconds < 10) seconds = "0" + seconds;
            return hours + ":" + minutes + " Hrs";
        },
        convertMinutes: function (intSeconds) {
            return Math.floor(intSeconds / this.secondsPerMinute)
        },
        convertHours: function (intSeconds) {
            var minutes = this.convertMinutes(intSeconds);
            var hours = Math.floor(minutes / this.minutesPerHour);
            return hours
        },
        getRemainingMinutes: function (intSeconds) {
            var intTotalMinutes = this.convertMinutes(intSeconds);
            return intTotalMinutes % this.minutesPerHour
        },
        getRemainingSeconds: function (intTotalSeconds) {
            return intTotalSeconds % this.secondsPerMinute
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                case "ApprovePopup":
                    this.ApprovePopup(item);
                    break;
                case "RejectPopup":
                    this.RejectPopup(item);
                    break;
            }
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                this.searchCondition = value.searchConditionJson;
            }
            else {
                this.searchCondition = "";
            }
            this.FetchData();
        },       
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
    renderActions: function (row) {
    var self = this;
    let rtnActionArray = [];

    self.listActions.forEach(actionItem => {
        let action = {
            ...actionItem
        };

        // Disable action if already approved or rejected
        if (row.IS_APPROVE_REJECT === 1 || row.IS_APPROVE_REJECT === 0) {
            action.isDisabled = true;
        } else {
            action.isDisabled = false;
        }

        action.isVisible = true;
        rtnActionArray.push(action);
    });

    return rtnActionArray;
},
        FetchData: function () {            
            var vm = this;
            vm.isLoading = true;
            var url = `sortBy=${vm.SortBy} &sortExp=${vm.SortExp}&pageSize=${vm.PageSize}&pageNumber=${vm.PageNumber}&taskName=${vm.TaskName}
                &title=${vm.Title}&status=${vm.Status}&userType=${vm.UserType} `;
            DataServices.RequestTimeList(url).then((response) => {                
                if (response.data.result != '') {
                    vm.RequestTimeData = response.data.result.DATA;
                    vm.TaskCountData = response.data.result.TASKDATA[0].taskCount;
                    vm.ApproveData = response.data.result.APPROVEDDATA[0].approveddata;
                    vm.RejectData = response.data.result.REJECTEDDATA[0].rejecteddata;
                    vm.PendingData = response.data.result.PENDINGDATA[0].pendingdata;
                    vm.Headers.forEach((column) => {
                        column.DISPLAY_NAME = vm.$t(column.DISPLAY_NAME ? column.DISPLAY_NAME : column.COLUMN_NAME);
                        column.settings = null;
                        if (column.COLUMN_NAME == "CREATED_AT" || column.COLUMN_NAME == "REQUEST_TIME_SEC" || column.COLUMN_NAME == 'Status' || column.COLUMN_NAME == 'ATTACHMENTFULLPATH' || column.COLUMN_NAME == 'REQUEST_COMMENT') {
                            column.settings = {
                                isInSlot: true,
                            }
                        }
                    });
                    vm.TotalRecords = response.data.result.DATA[0].TOTALRECORDS;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                    vm.noRecords = false;
                    vm.isLoading = false;
                }
                else {
                    vm.RequestTimeData = [];
                    vm.noRecords = true;
                    vm.TotalRecords = 0
                    vm.isLoading = false;
                }
            })
        }       
    }
}
</script>

<style>
.attachment-wrapper {
  position: relative;
  display: inline-block;
  cursor: pointer;
  text-align: center;
  width: 30px;  /* adjust as needed */
  height: 30px; /* adjust as needed */
  line-height: 30px; /* vertical center */
}

.attachment-wrapper em.fa-paperclip {
  font-size: 20px;
  color: #333;
}

.attachment-count {
  position: absolute;
  top: -5px;
  right: -5px;  /* changed from left to right */
  background: #17a2b8;
  color: white;
  font-size: 12px;
  font-weight: bold;
  border-radius: 50%;
  padding: 2px 6px;
  min-width: 18px;
  height: 18px;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 0 2px rgba(0,0,0,0.3);
  user-select: none;
  pointer-events: none;
}

.comment-wrapper {
  position: relative;
  display: inline-block;
  cursor: pointer;
  text-align: center;
  width: 30px;  /* adjust as needed */
  height: 30px; /* adjust as needed */
  line-height: 30px; /* vertical center */
}

.comment-wrapper em.fa-commenting-o {
  font-size: 20px;
  color: #333;
}

.comment-count {
  position: absolute;
  top: -5px;
  right: -5px;  /* changed from left to right */
  background: #17a2b8; /* light blue */
  color: white;
  font-size: 12px;
  font-weight: bold;
  border-radius: 50%;
  padding: 2px 6px;
  min-width: 18px;
  height: 18px;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 0 2px rgba(0,0,0,0.3);
  user-select: none;
  pointer-events: none;
}
</style>