<template lang="en">
  <section>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                     <h4 class="modal-title">
                        {{ $t('Request Title') }} : <span>{{ Title }}</span>
                        </h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                    </div>
                    <div class="modal-body">
                           <div class="modal-body">
                                <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                            </div>
                        <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 p-0">
                            <div id="accordion" class="w-100">
                                <div class="card" v-for="(groupItem, key, index) in groupByDate">
                                      <div class="card-header">
                                                <a :class="{ 'card-link collapsed': index > 1, 'card-link': index <= 1 }"
                                                    style="color:#000" data-toggle="collapse"
                                                    :href="'#collapseOneThread' + index">
                                                    <div class="conversation-date heading-border"><span>{{ headerFormatTime(key) }} </span></div>
                                                </a>
                                            </div>                                    <div>
                                         <div :id="'collapseOneThread' + index" :class="{ 'collapse': index > 1, 'collapse show': index <= 1 }">
                                            <div class="card-body">
                                                <div class="conversation-main">
                                                    <template v-for="(item, index) in groupItem">
                                                        <div class="conversation-time">
                                                            <span>{{ formatTime(item.createdAt) }}</span>
                                                        </div>
                                                        <div class="conversation-box-con">
                                                            <div class="conversation-box">
                                                                <div class="name-circle light-yellow">
                                                                    <img :src="item.avatar ? item.avatar : '/Content/images/DefaultImages/avatar-icon.jpg'" alt="Image" width="51" height="51" style="font-size:12px" loading="lazy" />
                                                                </div>
                                                                <div class="conversation-header addednote-ticket">
                                                                    <span class="sender-info">
                                                                        <span class="sender-name mr-2">{{ item.userName }}</span>
                                                                        <span class="sender-department mr-2">( {{$t('PostedOn')}} :</span><span class="sender-department" style="color : #dc3545!important"> 
                                                                            {{toPrettyString(item.createdAt) }}
                                                                        </span> <span class="sender-department">)</span>
                                                                    </span>
                                                                </div>
                                                                 <div class="conversation-content addednote-ticket">
                                                                     <p>{{ item.comment }}</p>
                                                                 </div>

                                                            </div>
                                                        </div>
                                                    </template>
                                                </div>
                                            </div>
                                        </div> 
                                    </div>
                                </div>
                            </div>
                       
                        </div>
                    </div>

                </div>
            </div>
        </div>
    </div>
  </section>
</template>

<script>
import DataService from '../../../services/DataService';
export default {
    props: {
        MessageBoardData: {
            type: Object,
            required: true
        }
    },
    data() {
        return {
            noRecord: false,
            TotalRecords: 0,
            isLoading: false,
            CommentList: [],
            startDate: '',
            endDate: '',
            isDisabled: false,
            Title: '',
            MessageBoardId: '',
            FormSchema: [{
                layoutType: "single",
                Data: [{
                    astype: "TextAreaField",
                    label: this.$t('Comment'),
                    name: "Comment",
                    value: "",
                    config: {
                        rows: 3
                    },
                    placeholder: this.$t('Enter Comment'),
                    validationRules: {
                        "required": true,
                        //"regex":/^[a-zA-Z0-9\s]*$/
                    },
                }]
            }],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible: true,

                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                },
            ],
        }
    },
      computed: {        
        groupByDate() {
            var vm = this;
            let groups = {};
            vm.CommentList.forEach(item => {
                let date = item.createdAt.substring(0, 10);
                if (groups[date]) {
                    groups[date].push(item);
                } else {
                    groups[date] = [item];
                }
            });
            return groups;
        }
    },
    async created() {
        debugger
        var vm = this;
        vm.MessageBoardId = this.MessageBoardData.MESSAGE_BOARD_ID;
        vm.Title = this.MessageBoardData.REQUEST_TITLE;
        vm.taskId= this.MessageBoardData.TASK_ID;
        vm.GetCommentList();
    },
    methods: {
        onSubmit(formfields, val) {
            debugger
            var vm = this;
            vm.isLoading = true;
            var jsonobj = {
                Title: vm.Title,
                Comment: formfields.Comment,
                MessageBoardId: vm.MessageBoardId,
            };
            var params = JSON.stringify(jsonobj);
            DataService.SaveCommentLog(params).then((response) => {
                if (response.data.result > 0) {
                    vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Comment')]), "success", true, vm.$t("Alert"));
                    vm.Close();
                    this.$parent.FetchData();
                    vm.isLoading = false;                
                }
            });
        },
        headerFormatTime: function (dateTimeString) {
            let dateTime = new Date(dateTimeString);
            // Options for formatting day, month, and year
            let options = {
                day: '2-digit',
                month: 'short',
                year: 'numeric'
            };
            // Format date to an array of parts
            let parts = dateTime.toLocaleDateString('en-GB', options).split(' ');
            // Construct the formatted date string with a comma
            let formattedDate = `${parts[0]} ${parts[1]}, ${parts[2]}`;
            return formattedDate;
        },
        toPrettyString(userDate) {
            const now = new Date();
            const date = new Date(userDate);
            const ts = Math.abs(now - date); // Time difference in milliseconds
            const delta = ts / 1000; // Convert milliseconds to seconds

            if (delta < 60) {
                return 'few seconds ago';
            }
            if (delta < 120) {
                return 'a minute ago';
            }
            if (delta < 2700) { // 45 * 60
                return `${Math.floor(delta / 60)} minutes ago`;
            }
            if (delta < 5400) { // 90 * 60
                return 'an hour ago';
            }
            if (delta < 86400) { // 24 * 60 * 60
                return `${Math.floor(delta / 3600)} hours ago`;
            }
            if (delta < 172800) { // 48 * 60 * 60
                return 'yesterday';
            }
            if (delta < 2592000) { // 30 * 24 * 60 * 60
                return `${Math.floor(delta / 86400)} days ago`;
            }
            if (delta < 31104000) { // 12 * 30 * 24 * 60 * 60
                const months = Math.floor(delta / (30 * 86400));
                return months <= 1 ? '1 month ago' : `${months} months ago`;
            }
            const years = Math.floor(delta / (365 * 86400));
            return years <= 1 ? '1 year ago' : `${years} years ago`;
        },
        formatTime(dateTimeString) {
            // Create a Date object from the provided date and time string
            let dateTime = new Date(dateTimeString);

            // Format the time using toLocaleTimeString()
            let formattedTime = dateTime.toLocaleTimeString([], {
                hour: '2-digit',
                minute: '2-digit'
            });

            return formattedTime;
        },        
        async GetCommentList() {
            debugger
            var vueObj = this;
            vueObj.isLoading = true;
            var params = `taskId=${vueObj.taskId}&messageBoardId=${vueObj.MessageBoardId}`;
            await DataService.RequestTimeCommentListing(params).then(response => {
                debugger
                if (response.data != "" && response.data != null) {
                    vueObj.CommentList = response.data[0].requestTimeCommentList;
                    vueObj.isLoading = false;
                } else {
                    vueObj.TotalRecords = 0
                    vueObj.CommentList = [];
                    vueObj.isLoading = false;
                }
                vueObj.isLoading = false;
            })
        },
        Close: function () {
            this.$parent.ShowAddComment = false;
        }
    }
}
</script>

<style>
.vue-slider-rail {
    background-color: #5bc0de !important;
}

.vue-slider-dot-handle {
    background-color: #5bc0de !important;
}

.conversation-box .name-circle {
    width: 61px !important;
    height: 61px !important;
    line-height: 41px !important;
}

textarea {
    resize: none !important;
}

.conversation-box .name-circle img {
    left: 2px !important;
    top: 2px !important;
}
</style>
