<template lang="en">
  <section>
    <div class="my-popups">
      <loader :is-visible="isLoading"></loader>
      <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered">
          <div class="modal-content">
            <div class="modal-header theme-primary partition-full d-flex">
              <h4 class="modal-title">{{ $t('Approval') }}</h4>
              <button type="button" class="close" v-on:click="Close">
                <em class="fa fa-times" aria-hidden="true"></em>
              </button>
            </div>
            <div class="modal-body">             
              <div class="input-group mb-4">
                <input  type="text" placeholder="HH" data-vv-as="Hours" name="Hours" class="form-control" v-model="ApprovedTime" aria-required="true" aria-invalid="false"/>
                <div class="input-group-append">
                  <span class="input-group-text">HH</span>
                </div>
                <span class="invalid-feedback text-left" style="display: none;"></span>
              </div> 
              <dynamic-form  lang="en" :buttons="buttons" :schema="FormSchema"  v-on:OnSubmit="onSubmit" :mandatorytext="MandatoryString" >
            </dynamic-form>              
            </div>
          </div>
        </div>
      </div>
    </div>
  </section>
</template>

<script>
import DataService from '../../../services/DataService';
export default {
    props: {
        MessageBoardData: {
            type: Object,
            required: true
        }
    },
    data() {
        return {
            noRecord: false,
            TotalRecords: 0,
            isLoading: false,
            CommentList: [],
            startDate: '',
            endDate: '',
            Type:'',  
            isDisabled: false,
            Title: '',
            MessageBoardId: '',                  
            FormSchema: [{                
                layoutType: "single",
                Data: [{
                    astype: "TextAreaField",
                    label: this.$t('Comment'),
                    name: "Comment",
                    value: "",
                    config: {
                        rows: 3
                    },
                    placeholder: this.$t('Enter Comment'),
                    validationRules: {
                        "required": true,
                        //"regex":/^[a-zA-Z0-9\s]*$/
                    },
                }]
            }],
            buttons: [{
                type: "submit",
                class: "btn btn-success",
                text: "<i class='fa fa-save pr-2'></i>Save",
                isVisible: true,
            },
            {
                type: "button",
                class: "btn btn-danger",
                text: "<i class='fa fa-close pr-2'></i>Cancel",
                onClick: this.Close,
            },
            ],
        }
    },
    computed: {
        groupByDate() {
            var vm = this;
            let groups = {};
            vm.CommentList.forEach(item => {
                let date = item.createdAt.substring(0, 10);
                if (groups[date]) {
                    groups[date].push(item);
                } else {
                    groups[date] = [item];
                }
            });
            return groups;
        }
    },    
    async created() {
        debugger
        var vm = this;
        vm.MessageBoardId = this.MessageBoardData.MESSAGE_BOARD_ID;
        vm.taskId = this.MessageBoardData.TASK_ID;
        vm.ApprovedTime = this.MessageBoardData.APPROVED_TIME
        vm.RequestCreateByID=this.MessageBoardData.CREATED_BY
        vm.requestTimeId=this.MessageBoardData.REQUEST_TIME_ID
        vm.requestTime=this.MessageBoardData.REQUEST_TIME_SEC
        vm.ProjectId=this.MessageBoardData.PROJECT_ID
        vm.GetCommentList();
    },
    methods: {
            async onSubmit(formfields, val) {
            debugger
            const vm = this;
            vm.isLoading = true;
            const jsonobj = {
                MessageBoardId: vm.MessageBoardId,
                Type: 'Approved',
                Comment: formfields.Comment,
                ProjectId: vm.ProjectId,
                TaskId: vm.taskId,
                RequestTimeId: vm.requestTimeId,
                ApprovedTime: vm.ApprovedTime,
                RequestCreateBy: vm.RequestCreateByID,
            };
        const params = JSON.stringify(jsonobj);

            await DataService.RequestTimApprovalRejecteTime(params).then(async(response) => {
                debugger
                if (response.data.status === "Success") {
                     const Obj = {
                        TypeCode: '',
                        ProjectId: vm.ProjectId,
                    };
                    await DataService.GetActivityResult(Obj).then(response => {
                        debugger
                            if(response.data.status == "Success"){
                                vm.ShowAlert(vm.$t('Request Time has been approved successfully'), "success", true, vm.$t("Alert"));
                                vm.$parent.FetchData();
                                vm.Close();
                            }
                        })
                } 
                vm.isLoading = false;
            })
        },
        Close: function () {
            this.$parent.ShowApprovalPopup = false;
        }        
    }
}
</script>
